INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Jesus Rodrigues$pf$,$pf$Jesus Rodrigues$pf$,'jesus-rodrigues','PI','Governador',$pf$Cidadania$pf$,'CIDADANIA','pre-candidato','pre-candidato',$pf$Jesus Rodrigues é economista, produtor rural e ex-deputado federal pelo Piauí. Formado em Ciências Econômicas pela Universidade Federal do Piauí (UFPI), cumpriu mandato de deputado federal entre 2011 e 2015. Em 2026 é pré-candidato ao Governo do Piauí pelo Cidadania, partido que decidiu reativar após não conseguir espaço para seu projeto majoritário em outras siglas da esquerda.$pf$,'https://upload.wikimedia.org/wikipedia/commons/2/23/DeputadoJesusRodriguesPIAUI.JPG',true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='jesus-rodrigues');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','CIDADANIA',2026,NULL,$pf$Filiacao partidaria (Wikipedia): PT (1994-2015), PSOL (2015-2024), Solidariedade (2024-2026) e Cidadania (2026-presente). Pré-candidato ao Governo do PI em 2026 pelo Cidadania. Fonte: https://pt.wikipedia.org/wiki/Jesus_Rodrigues$pf$ FROM candidatos c WHERE c.slug='jesus-rodrigues' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Elizeu Aguiar$pf$,$pf$Elizeu Aguiar$pf$,'elizeu-aguiar','PI','Governador',$pf$Partido Novo$pf$,'NOVO','pre-candidato','pre-candidato',$pf$Elizeu Aguiar é empresário com longa trajetória na política do Piauí. Foi vereador de Teresina (eleito em 2004, reeleito em 2008, pelo PTB) e exerceu mandato de deputado federal como suplente entre janeiro de 2009 e abril de 2010. Em 2022 disputou deputado estadual pelo Progressistas, sem se eleger (3.231 votos). Foi oficializado em abril de 2026 como pré-candidato ao Governo do Piauí pelo Partido Novo, defendendo uma alternativa liberal com pauta de redução de impostos e geração de emprego.$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='elizeu-aguiar');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','NOVO',2026,NULL,$pf$Foi vereador de Teresina pelo PTB (2005-2009); disputou deputado estadual pelo Progressistas em 2022. Oficializado pré-candidato ao Governo do PI em abril de 2026 pelo Partido Novo. Fontes: piauihoje.com (oficializacao Novo) e portalclubenews.com.$pf$ FROM candidatos c WHERE c.slug='elizeu-aguiar' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Geraldo Carvalho$pf$,$pf$Geraldo Carvalho$pf$,'geraldo-carvalho','PI','Governador',$pf$Partido Socialista dos Trabalhadores Unificado$pf$,'PSTU','pre-candidato','pre-candidato',$pf$Geraldo Carvalho é sociólogo e professor da Universidade Federal do Piauí (UFPI), com atuação no movimento sindical desde o fim dos anos 1980. Foi presidente do Sindicato dos Bancários e dirigente do Sindicato Nacional dos Docentes das Instituições de Ensino Superior (Andes-SN). Já disputou o Governo do Piauí em 2022 pelo PSTU (6º lugar, 0,07% dos votos válidos) e foi anunciado novamente pelo partido, em 7 de abril de 2026, como pré-candidato ao governo, com plataforma socialista voltada à classe trabalhadora.$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='geraldo-carvalho');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','PSTU',2026,NULL,$pf$Filiado ao PSTU; candidato ao Governo do PI pelo PSTU em 2022 e pré-candidato pela mesma legenda em 2026 (anunciado em 07/04/2026). Fontes: piauihoje.com e Portal AZ.$pf$ FROM candidatos c WHERE c.slug='geraldo-carvalho' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Francisco Jurity$pf$,$pf$Francisco Jurity$pf$,'francisco-jurity','PI','Governador',$pf$Democracia Crista$pf$,'DC','pre-candidato','pre-candidato',$pf$Francisco Jurity é professor aposentado e empresário, e dirigente partidário que deve encabeçar a chapa da Democracia Cristã (DC) no Piauí após a reorganização da legenda no estado. Já disputou uma vaga de deputado federal em 2010, sem se eleger. Como pré-candidato ao Governo do Piauí em 2026, defende geração de emprego para jovens, desenvolvimento do estado e subsídio a energia limpa para atrair indústrias.$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='francisco-jurity');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','DC',2026,NULL,$pf$Dirigente da Democracia Cristã (DC) no Piauí; pré-candidato ao Governo do PI em 2026 pela DC. Disputou deputado federal em 2010 sem eleger-se. Fonte: ndmais.com.br e Portal O Dia.$pf$ FROM candidatos c WHERE c.slug='francisco-jurity' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Ravenna Castro$pf$,$pf$Ravenna Castro$pf$,'ravenna-castro','PI','Governador',$pf$Democrata$pf$,'D35','pre-candidato','pre-candidato',$pf$Ravenna Castro é advogada e jornalista, presidente do Partido Democrata no Piauí. Já tem experiência em disputas majoritárias: foi candidata ao Governo do Piauí em 2022 pelo PMN (Partido da Mobilização Nacional) e disputou a Prefeitura de Teresina em 2024. Em 2026 é pré-candidata ao Governo do Piauí encabeçando a chapa do Democrata.$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='ravenna-castro');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','D35',2026,NULL,$pf$Disputou o Governo do PI em 2022 pelo PMN; em 2026 preside e encabeça a chapa do 'Democrata' no Piauí. ATENCAO: as fontes de imprensa usam o nome 'Democrata'/'Partido Democrata' (input do PuxaFicha trazia 'Democratas'); a sigla/numero TSE exata nao foi confirmada nesta pesquisa e deve ser checada antes de publicar. Fontes: ndmais.com.br e meionews.com.$pf$ FROM candidatos c WHERE c.slug='ravenna-castro' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Gisvaldo Oliveira$pf$,$pf$Gisvaldo Oliveira$pf$,'gisvaldo-oliveira','PI','Governador',$pf$Partido Socialismo e Liberdade$pf$,'PSOL','pre-candidato','pre-candidato',$pf$Gisvaldo Oliveira é professor universitário formado em História, com atuação em Floriano (PI). Em 2025 disputou a reitoria da Universidade Estadual do Piauí (Uespi). Foi lançado pela federação PSOL/Rede Sustentabilidade como pré-candidato ao Governo do Piauí em 2026, com candidatura voltada a pautas sociais, ambientais e de direitos humanos.$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='gisvaldo-oliveira');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','PSOL',2026,NULL,$pf$Filiado ao PSOL; lançado pela federação PSOL/Rede Sustentabilidade como pré-candidato ao Governo do PI em 2026. Fonte: Portal O Dia (blog Piauí) e blogdobsilva.com.br.$pf$ FROM candidatos c WHERE c.slug='gisvaldo-oliveira' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Gustavo Henrique$pf$,$pf$Gustavo Henrique$pf$,'gustavo-henrique','PI','Governador',$pf$Avante$pf$,'AVANTE','pre-candidato','pre-candidato',$pf$Gustavo Henrique é bacharel em Direito e presidente estadual do Avante no Piauí, cargo que assumiu após mudança no comando do partido no estado. Natural de Belo Horizonte (MG), já foi candidato ao Senado em 2014 (pelo PSC) e a vereador de Teresina em 2020 (pelo Avante). Em junho de 2026 o Avante oficializou sua pré-candidatura ao Governo do Piauí.$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='gustavo-henrique');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','AVANTE',2026,NULL,$pf$Presidente estadual do Avante no PI (sucedeu Michel Saldanha); antes disputou Senado em 2014 pelo PSC e vereador de Teresina em 2020 pelo Avante. Pré-candidatura ao Governo do PI oficializada pelo Avante em junho de 2026. Fonte: Portal O Dia e Cidade Verde.$pf$ FROM candidatos c WHERE c.slug='gustavo-henrique' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Santiago Belizário$pf$,$pf$Santiago Belizário$pf$,'santiago-belizario','PI','Governador',$pf$Unidade Popular$pf$,'UP','pre-candidato','pre-candidato',$pf$Santiago Belizário é historiador e militante da Unidade Popular (UP) desde a fundação do partido, com atuação no Movimento de Luta nos Bairros, Vilas e Favelas (MLB). Já foi candidato a prefeito de Teresina em eleição municipal recente. Em 31 de maio de 2026, a direção estadual da UP o definiu como pré-candidato ao Governo do Piauí, com Thays Dias (coordenadora do Movimento de Mulheres Olga Benário) como pré-candidata a vice.$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='santiago-belizario');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','UP',2026,NULL,$pf$Militante da Unidade Popular (UP) desde a fundação; definido pela direção estadual da UP como pré-candidato ao Governo do PI em 31/05/2026 (anúncio oficial previsto para 12/06/2026). Fonte: Portal O Dia (blog Piauí) e Cidade Verde.$pf$ FROM candidatos c WHERE c.slug='santiago-belizario' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Izalci Lucas$pf$,$pf$Izalci Lucas$pf$,'izalci-lucas','DF','Governador',$pf$Partido Liberal$pf$,'PL','pre-candidato','pre-candidato',$pf$Izalci Lucas (Izalci Lucas Ferreira) e senador pelo Distrito Federal e pre-candidato ao Governo do DF em 2026 pelo PL. Nascido em 7 de abril de 1956, em Araujos (MG), e contador de profissao. Foi deputado distrital (2003-2007) e deputado federal pelo DF (2007-2019) antes de se eleger senador em 2018, mandato 2019-2027. Em abril de 2026 anunciou em plenario sua pre-candidatura ao Palacio do Buriti, defendendo que o PL, maior partido do pais, deveria ter candidato proprio, e afirmando estar em terceiro lugar nas pesquisas. Mantem a pre-candidatura mesmo diante de divergencias internas do PL sobre apoiar a governadora Celina Leao.$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='izalci-lucas');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','PL',2026,NULL,$pf$Historico partidario: iniciou na vida politica em 1997. Deputado distrital pelo PFL (2003-2006); deputado federal pelo PFL/DEM (2007-2011), depois PR (2011-2015) e PSDB (2015-2019); senador eleito pelo PSDB (mandato 2019-2027). Em 26-27 de marco de 2024 filiou-se ao PL, em cerimonia em Brasilia com presenca de Valdemar Costa Neto e do ex-presidente Jair Bolsonaro, deixando o PSDB onde era lider no Senado. Fonte: https://www.poder360.com.br/partidos-politicos/com-aval-de-bolsonaro-e-valdemar-izalci-lucas-se-filia-ao-pl/ ; https://www.congressoemfoco.com.br/noticia/8688/izalci-deixa-psdb-e-vai-para-o-pl-tucanos-ficam-com-somente-um ; biografia Camara https://www.camara.leg.br/deputados/4931/biografia$pf$ FROM candidatos c WHERE c.slug='izalci-lucas' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Kiko Caputo$pf$,$pf$Kiko Caputo$pf$,'kiko-caputo','DF','Governador',$pf$Partido Novo$pf$,'NOVO','pre-candidato','pre-candidato',$pf$Kiko Caputo (Francisco Queiroz Caputo Neto) e advogado e pre-candidato ao Governo do Distrito Federal em 2026 pelo partido Novo. Tem graduacao em Direito e pos-graduacao em Direito e Processo do Trabalho. Foi presidente da OAB-DF entre 2010 e 2012 e atuou por 32 anos na advocacia, incluindo passagem como conselheiro seccional e conselheiro federal da OAB. Em fevereiro de 2026 renunciou ao cargo de membro suplente do Conselho Federal da OAB para viabilizar a candidatura. Esta sera sua primeira disputa por cargo eletivo. Sua plataforma enfatiza transparencia, gestao eficiente e reforma administrativa.$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='kiko-caputo');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','NOVO',2026,NULL,$pf$Filiacao partidaria: nao tinha filiacao a cargo eletivo anterior (primeira disputa). Anunciou que vai se filiar ao Novo para concorrer ao GDF; o partido Novo lancou oficialmente sua pre-candidatura em evento em 22 de abril de 2026, no Minas Tennis Club em Brasilia, com presenca do governador de Minas Gerais Romeu Zema. Antes da entrada na politica partidaria, sua trajetoria foi institucional na OAB-DF (presidente 2010-2012, conselheiro federal). Fonte: https://oantagonista.com.br/brasil/novo-lanca-pre-candidatura-de-kiko-caputo-ao-governo-do-df/ ; https://blogs.correiobraziliense.com.br/cbpoder/ao-lado-de-zema-novo-lanca-pre-candidatura-de-kiko-caputo-ao-buriti/$pf$ FROM candidatos c WHERE c.slug='kiko-caputo' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Antonia Pedrosa$pf$,$pf$Antonia Pedrosa$pf$,'antonia-pedrosa','RR','Governador',$pf$Partido dos Trabalhadores$pf$,'PT','pre-candidato','pre-candidato',$pf$Antônia Pedrosa Vieira é professora da rede pública e servidora, com trajetória ligada à educação pública, direitos humanos e movimentos sociais em Roraima. É graduada em Pedagogia e mestre em Educação pela Universidade Federal de Roraima (UFRR), e atuou como liderança sindical e como vereadora em Boa Vista. Militante do PT, foi anunciada em 8 de março de 2026 como pré-candidata do partido ao Governo de Roraima em 2026. ATENÇÃO/CONTEXTO: em 1º de junho de 2026, sua candidatura na eleição suplementar foi substituída por Nelita Frank (mediante autorização do ministro Flávio Dino, do STF), por não cumprimento do prazo de desincompatibilização exigido pela Justiça Eleitoral.$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='antonia-pedrosa');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','PT',2026,NULL,$pf$Filiada ao PT (militante há mais de 15 anos), na federação Brasil da Esperança (PT/PV/PCdoB). Anunciada como pré-candidata do PT ao Governo de Roraima em 8 de março de 2026, substituindo o advogado Jocelino Pereira, que desistiu por motivos pessoais. Na chapa, o vice é a liderança indígena Bartô Macuxi (PSOL), em aliança com a federação PSOL-Rede. Em 1º de junho de 2026, foi substituída por Nelita Frank na eleição suplementar por questões de desincompatibilização. Fonte: https://www.folhabv.com.br/politica/antonia-pedrosa-e-anunciada-como-pre-candidata-ao-governo-pelo-pt-em-roraima/ e https://pt.wikipedia.org/wiki/Eleição_suplementar_para_governador_de_Roraima_em_2026$pf$ FROM candidatos c WHERE c.slug='antonia-pedrosa' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Rafael Duda$pf$,$pf$Rafael Duda$pf$,'rafael-duda','MG','Governador',$pf$Partido Socialista dos Trabalhadores Unificado$pf$,'PSTU','pre-candidato','pre-candidato',$pf$Rafael Duda (nome de registro Rafael Ribeiro de Ávila) é pré-candidato ao Governo de Minas Gerais em 2026 pelo PSTU. É trabalhador da mineração e dirigente do Metabase Inconfidentes, sindicato que representa trabalhadores da extração de minério de ferro e metais básicos na região de Congonhas, Belo Vale e Ouro Preto. Já disputou eleições anteriores: candidato a prefeito de Congonhas em 2020 e 2024 e a deputado federal em 2022. Apresenta uma plataforma socialista voltada à classe trabalhadora.$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='rafael-duda');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','PSTU',2026,NULL,$pf$Pré-candidato ao Governo de MG em 2026 pelo PSTU, lançado pelo partido em janeiro de 2026. Já foi candidato a prefeito de Congonhas (2020, 2024) e a deputado federal (2022). Fonte: Wikipédia (Eleições estaduais em Minas Gerais em 2026) e O Tempo (07/01/2026).$pf$ FROM candidatos c WHERE c.slug='rafael-duda' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Henrique Áreas$pf$,$pf$Henrique Áreas$pf$,'henrique-areas','MG','Governador',$pf$Partido da Causa Operaria$pf$,'PCO','pre-candidato','pre-candidato',$pf$Henrique Áreas (nome completo Henrique Áreas de Araujo) é pré-candidato ao Governo de Minas Gerais em 2026 pelo PCO (Partido da Causa Operária). Sem cargo político anterior, segundo a documentação eleitoral. Em sua plataforma, defende a reestatização de empresas privatizadas e faz forte crítica à política de privatizações, atribuindo a desastres da mineração em Minas ao modelo iniciado nos governos do PSDB.$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='henrique-areas');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','PCO',2026,NULL,$pf$Pré-candidato ao Governo de MG em 2026 pelo PCO, dentro da lista de pré-candidaturas estaduais do partido. Sem cargo político anterior. Fonte: Wikipédia (Eleições estaduais em Minas Gerais em 2026) e Diário Causa Operária / PCO.$pf$ FROM candidatos c WHERE c.slug='henrique-areas' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Indira Xavier$pf$,$pf$Indira Xavier$pf$,'indira-xavier','MG','Governador',$pf$Unidade Popular$pf$,'UP','pre-candidato','pre-candidato',$pf$Indira Xavier (nome completo Indira Ivanise Xavier) é pré-candidata ao Governo de Minas Gerais em 2026 pela Unidade Popular (UP). Nascida em Maceió (AL) em 4 de outubro de 1984, é professora e ativista de direitos humanos, com militância em movimentos sociais feministas e pela habitação popular. Coordena o Movimento de Mulheres Olga Benário e a ocupação Casa Tina Martins. Filiada à UP desde 2019, já foi candidata ao Governo de MG em 2022 e à Prefeitura de Belo Horizonte em 2024, sem se eleger.$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='indira-xavier');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','UP',2026,NULL,$pf$Filiada à Unidade Popular (UP) desde 2019. Pré-candidata ao Governo de MG em 2026 (segunda disputa ao governo, após 2022); também foi candidata à Prefeitura de BH em 2024. Fonte: CNN Brasil, Assembleia Legislativa de MG (ALMG) e Metrópoles.$pf$ FROM candidatos c WHERE c.slug='indira-xavier' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Vittorio Medioli$pf$,$pf$Vittorio Medioli$pf$,'vittorio-medioli','MG','Governador',$pf$Partido Liberal$pf$,'PL','pre-candidato','pre-candidato',$pf$Vittorio Medioli é pré-candidato ao Governo de Minas Gerais em 2026 pelo PL. Nascido em 3 de maio de 1951, italiano naturalizado brasileiro na década de 1980, é empresário fundador do Grupo SADA (originado no setor de transportes e hoje com mais de 30 empresas em diversos segmentos). Foi deputado federal por quatro mandatos pelo PSDB (1991-2007) e prefeito de Betim por dois mandatos (eleito em 2016 e reeleito em 2020 com cerca de 76% dos votos). Filiou-se ao PL em 2022 e surgiu como pré-candidato ao governo, defendendo austeridade fiscal aliada a uma visão humanista dos problemas sociais e criticando a gestão de Romeu Zema.$pf$,'https://upload.wikimedia.org/wikipedia/commons/4/48/2016_VITTORIO_MEDIOLI_CANDIDATO_PREFEITO_MG_BETIM_TSE_%28130000080259%29.jpg',true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='vittorio-medioli');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','PL',2026,NULL,$pf$Deputado federal pelo PSDB por quatro mandatos (1991-2007); prefeito de Betim 2017-2024 (PSD na reeleição de 2020). Filiou-se ao PL em 2022; em 2026 é pré-candidato ao Governo de MG pelo PL. Fonte: Wikipédia (Vittorio Medioli), O Tempo (26/06/2026) e CNN Brasil.$pf$ FROM candidatos c WHERE c.slug='vittorio-medioli' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Mário Couto$pf$,$pf$Mário Couto$pf$,'mario-couto','PA','Governador',$pf$Democracia Crista$pf$,'DC','pre-candidato','pre-candidato',$pf$Mário Couto Filho, nascido em 14 de janeiro de 1946 em Soure (PA), é administrador de empresas e político de longa trajetória no Pará. Foi deputado estadual por quatro mandatos consecutivos (1991 a 2007), tendo presidido a Assembleia Legislativa do Pará (ALEPA), e senador da República pelo Pará de 2007 a 2015. Em 2026 é pré-candidato ao Governo do Pará. Sua filiação partidária mudou várias vezes ao longo da pré-campanha: buscou aval do PL em 2025, anunciou ida ao Partido Novo em 1º de abril de 2026 e, após divergências sobre fundo eleitoral, filiou-se à Democracia Cristã em abril de 2026.$pf$,'https://upload.wikimedia.org/wikipedia/commons/b/b5/Mario_couto_senador.JPG',true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='mario-couto');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','DC',2026,NULL,$pf$Trajetória partidária (fonte: Wikipedia pt e Uruá-Tapera 09/04/2026): PDS (1990-1993) > PMDB (1993-1995) > PSDB (1995-2015, período em que foi deputado estadual e senador) > PP (2017) > PRTB > PL (2022-2026) > Novo (filiação anunciada 01/04/2026) > Democracia Cristã (DC), filiado em abril de 2026, partido da base governista no Pará. IMPORTANTE: o partido informado na tarefa e na fonte original (Coluna Olavo Dutra) era PL, refletindo o estágio de 2025; a filiação ao PL foi superada e o partido atual confirmado é a Democracia Cristã (DC).$pf$ FROM candidatos c WHERE c.slug='mario-couto' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Raquel Brício$pf$,$pf$Raquel Brício$pf$,'raquel-bricio','PA','Governador',$pf$Unidade Popular$pf$,'UP','pre-candidato','pre-candidato',$pf$Raquel Nonato de Brício, nascida em 12 de outubro de 1991 em Moju (PA), mudou-se para Belém aos 12 anos. É guarda portuária federal na Companhia Docas do Pará e diretora do Sindicato dos Portuários do Pará e Amapá (Sindiporto PA/AP). Tem formação em gestão de recursos humanos e cursa Direito na Universidade Federal do Pará (UFPA). Iniciou a militância no movimento estudantil, tendo sido presidente do grêmio estudantil em 2007 no atual Instituto Federal do Pará. Já disputou eleições anteriores: candidata a vereadora de Belém em 2020, a deputada estadual em 2022 e a prefeita de Belém pela Unidade Popular em 2024 (número 80), sem ser eleita. Em 2026 é pré-candidata ao Governo do Pará pela Unidade Popular.$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='raquel-bricio');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','UP',2026,NULL,$pf$Presidente estadual da Unidade Popular (UP) no Pará. Filiação à UP confirmada pelas candidaturas pela legenda: pré-candidata a prefeita de Belém pela UP em 2024 (nº 80) e pré-candidata ao Governo do Pará pela UP anunciada em maio de 2026 (fonte: Estado do Pará Online; Wikipedia eleição estadual 2026 PA). Atenção: uma matéria da CNN Brasil rotulou a sigla incorretamente como 'União Brasil'; o partido correto é Unidade Popular (UP).$pf$ FROM candidatos c WHERE c.slug='raquel-bricio' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Telêmaco Brandão$pf$,$pf$Telêmaco Brandão$pf$,'telemaco-brandao','GO','Governador',$pf$Partido Novo$pf$,'NOVO','pre-candidato','pre-candidato',$pf$Telêmaco Brandão é advogado, empresário e ex-vereador de Goiânia, filiado ao NOVO, e pré-candidato ao Governo de Goiás em 2026. Foi o primeiro vereador eleito pelo NOVO na Câmara Municipal de Goiânia (eleito como suplente em 2020, assumiu a cadeira em setembro). Atua também como comentarista político em veículos de mídia de Goiás. Sua plataforma de pré-candidatura defende Estado mínimo, redução de impostos e responsabilidade fiscal, posicionando-se no campo da direita.$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='telemaco-brandao');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','NOVO',2026,NULL,$pf$Filiado ao NOVO. Concorreu a vereador de Goiânia pelo NOVO em 2020 (primeiro vereador do partido na capital); pré-candidato ao Governo de Goiás pelo NOVO em 2026. Fontes: página oficial da Câmara Municipal de Goiânia (https://goiania.go.leg.br/institucional/parlamentares/Telemaco-Brandao) e Poder Goiás (https://www.podergoias.com.br/materia/22813/partido-novo-lanca-telemaco-brandao-como-pre-candidato-ao-governo).$pf$ FROM candidatos c WHERE c.slug='telemaco-brandao' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Huggo Leonardo$pf$,$pf$Huggo Leonardo$pf$,'huggo-leonardo','CE','Governador',$pf$Partido Missao$pf$,'MISSAO','pre-candidato','pre-candidato',$pf$Huggo Leonardo, conhecido como Delegado Huggo, é pré-candidato ao Governo do Ceará em 2026 pelo partido Missão. Delegado da Polícia Civil do Ceará (PCCE) desde 2018 e graduado em Direito, tem 37 anos e nasceu no bairro Vicente Pinzón, em Fortaleza. Inicialmente lançado como pré-candidato ao Senado em 7 de maio de 2026, redirecionou sua candidatura para o Governo do Estado dias depois, a convite do presidente nacional do Missão, Renan Santos. Em maio de 2026 foi afastado preventivamente do cargo de delegado por decisão da Controladoria Geral de Disciplina.$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='huggo-leonardo');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','MISSAO',2026,NULL,$pf$Filiado ao partido Missão. Lançado pré-candidato ao Senado pelo Missão em 7 de maio de 2026; convertido em pré-candidato ao Governo do Ceará em meados de maio de 2026, a convite do presidente nacional do partido, Renan Santos. Fonte: O Povo (15/05/2026 e 26/05/2026).$pf$ FROM candidatos c WHERE c.slug='huggo-leonardo' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Giovanni Sampaio$pf$,$pf$Giovanni Sampaio$pf$,'giovanni-sampaio','CE','Governador',$pf$Partido Renovacao Democratica$pf$,'PRD','pre-candidato','pre-candidato',$pf$Giovanni Sampaio é pré-candidato ao Governo do Ceará em 2026 pelo PRD (Partido Renovação Democrática). Médico, foi vice-prefeito de Juazeiro do Norte e ex-diretor do Hospital Regional do Cariri durante o governo de Elmano de Freitas. Filiou-se ao PRD em 3 de abril de 2026, no último dia da janela partidária, depois de passar por PSB e Republicanos, para viabilizar sua pré-candidatura ao governo estadual.$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='giovanni-sampaio');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','PRD',2026,NULL,$pf$Trajetória partidária: passou por PSB e Republicanos; filiou-se ao PRD em 3 de abril de 2026 (último dia da janela), colocando o nome à disposição para disputar o Governo do Ceará. Fonte: O Povo (07/04/2026 e 26/05/2026).$pf$ FROM candidatos c WHERE c.slug='giovanni-sampaio' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Jarir Pereira$pf$,$pf$Jarir Pereira$pf$,'jarir-pereira','CE','Governador',$pf$Partido Socialismo e Liberdade$pf$,'PSOL','pre-candidato','pre-candidato',$pf$Jarir Pereira é pré-candidato ao Governo do Ceará em 2026 pelo PSOL. Professor da rede estadual de ensino há mais de dez anos e dirigente do sindicato dos professores APEOC, integra a Executiva Estadual do partido. Foi escolhido pré-candidato em deliberação do diretório estadual do PSOL Ceará em 19 de dezembro de 2025, anúncio feito pelo presidente estadual da legenda, Alexandre Uchoa, marcando uma candidatura própria do partido ao governo (em 2022 o PSOL havia retirado candidatura para apoiar Elmano de Freitas).$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='jarir-pereira');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','PSOL',2026,NULL,$pf$Filiado ao PSOL, membro da Executiva Estadual. Escolhido pré-candidato ao Governo do Ceará em deliberação do diretório estadual em 19 de dezembro de 2025. Fonte: Diário do Nordeste (coluna Wagner Mendes) e O Povo (26/05/2026).$pf$ FROM candidatos c WHERE c.slug='jarir-pereira' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Zé Batista$pf$,$pf$Zé Batista$pf$,'ze-batista','CE','Governador',$pf$Partido Socialista dos Trabalhadores Unificado$pf$,'PSTU','pre-candidato','pre-candidato',$pf$Zé Batista é pré-candidato ao Governo do Ceará em 2026 pelo PSTU (Partido Socialista dos Trabalhadores Unificado), do qual é presidente no estado. Operário da construção civil natural de Iguatu, no interior do Ceará, começou como pedreiro e é dirigente sindical da Central Sindical e Popular Conlutas (CSP-Conlutas). Foi oficializado pré-candidato em evento em Fortaleza em junho de 2026, confirmando decisão tomada por militantes do partido em março. É a segunda vez que disputa o Governo do Ceará; também foi candidato a prefeito de Fortaleza em 2024 e a vereador em 2020. Na eleição para governador de 2022 recebeu 1.507 votos (0,03% dos válidos).$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='ze-batista');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','PSTU',2026,NULL,$pf$Filiado ao PSTU, presidente do partido no Ceará. Escolha como pré-candidato definida por militantes em março de 2026 e oficializada em evento em Fortaleza em junho de 2026. Fonte: Diário do Nordeste (PontoPoder, jun/2026) e O Povo (26/05/2026).$pf$ FROM candidatos c WHERE c.slug='ze-batista' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Olímpio Rocha$pf$,$pf$Olímpio Rocha$pf$,'olimpio-rocha','PB','Governador',$pf$Partido Socialismo e Liberdade$pf$,'PSOL','pre-candidato','pre-candidato',$pf$Olímpio Rocha é pré-candidato ao Governo da Paraíba em 2026 pelo PSOL. É advogado popular há mais de 15 anos, professor de Direito e mestre e doutorando em Direitos Humanos pela Universidade Federal da Paraíba (UFPB). Atua na defesa de direitos humanos junto a movimentos sociais urbanos e rurais. Foi presidente do Conselho Estadual de Direitos Humanos da Paraíba, onde se destacou na campanha Despejo Zero, com decisões judiciais que beneficiaram mais de 5 mil famílias paraibanas. É primeiro suplente de deputado estadual pelo PSOL. Foi candidato a prefeito de Campina Grande em 2020, registrando a maior votação do PSOL no município. A pré-candidatura foi oficializada pelo PSOL em plenária em João Pessoa, em fevereiro de 2026, após Lúcio Flávio declinar e apoiar seu nome.$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='olimpio-rocha');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','PSOL',2026,NULL,$pf$Filiado ao PSOL (Partido Socialismo e Liberdade). Primeiro suplente de deputado estadual pelo PSOL. Candidato a prefeito de Campina Grande pelo PSOL em 2020. Pré-candidatura ao Governo da Paraíba oficializada pelo PSOL em plenária em João Pessoa em 28 de fevereiro de 2026. Fontes: site oficial olimpiorocha2026.com.br; Termômetro da Política; Parlamento PB; Jornal da Paraíba.$pf$ FROM candidatos c WHERE c.slug='olimpio-rocha' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$André Luís$pf$,$pf$André Luís$pf$,'andre-luis','MA','Governador',$pf$Partido Missao$pf$,'MISSAO','pre-candidato','pre-candidato',$pf$André Luís é pré-candidato ao Governo do Maranhão em 2026 pelo Partido Missão. Segundo a imprensa, ele e os demais pré-candidatos do Missão têm origem no Movimento Brasil Livre (MBL), e ele tenta reproduzir no estado a estratégia de Renan Santos (pré-candidato do partido à Presidência), apostando em discurso liberal e conservador nas redes sociais com a promessa de "moralizar e industrializar o Maranhão". Seu perfil no Instagram tinha pouco mais de 6.400 seguidores. Não foram localizadas, em fontes públicas, informações verificadas sobre nome completo, idade, profissão ou cargos anteriores.$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='andre-luis');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','MISSAO',2026,NULL,$pf$Filiado ao Partido Missão, legenda originada do Movimento Brasil Livre (MBL) e reconhecida pelo TSE em 4 de novembro de 2025 (30º partido registrado no Brasil, número 14). É apontado como pré-candidato ao governo do Maranhão pelo Missão em 2026. Fontes: https://pt.wikipedia.org/wiki/Partido_Miss%C3%A3o ; https://www.gazetadopovo.com.br/eleicoes/2026/partido-missao-geracao-z-amplia-lista-pre-candidatos-governador/ ; https://ndmais.com.br/politica/quem-e-pre-candidato-nas-eleicoes-no-maranhao-2026/$pf$ FROM candidatos c WHERE c.slug='andre-luis' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Renan Hallais$pf$,$pf$Renan Hallais$pf$,'renan-hallais','PE','Governador',$pf$Partido Missao$pf$,'MISSAO','pre-candidato','pre-candidato',$pf$Renan Hallais é pré-candidato ao Governo de Pernambuco em 2026 pelo partido Missão (legenda recém-criada, ligada ao Movimento Brasil Livre/MBL). Tem 35 anos, é de Recife, formado em Contabilidade e pós-graduado em Finanças, Investimentos e Banking. É coordenador do MBL em Pernambuco, ativista político de direita/conservador e atua como diretor jornalístico do portal 'O Brasil de Cima' (BDC). Sua pré-candidatura foi confirmada pelo partido Missão durante a passagem por Pernambuco de Renan Santos, pré-candidato da sigla à Presidência da República. O perfil técnico é apresentado pelo partido como alinhado a uma proposta de gestão focada em responsabilidade fiscal e planejamento administrativo.$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='renan-hallais');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','MISSAO',2026,NULL,$pf$Coordenador do Movimento Brasil Livre (MBL) em Pernambuco (fonte: legenda da entrevista no Instagram, https://www.instagram.com/reel/DT_RsXXD6Qz/). Em janeiro de 2026 teve a pré-candidatura ao Governo de PE confirmada pelo partido Missão, legenda recém-criada e ligada ao MBL (fontes: https://www.blogdomarioflavio.com.br/renan-hallais-e-confirmado-pelo-missao-pre-candidato-ao-governo-de-pernambuco/ e https://www.instagram.com/p/DTjVRj4DIjo/). Não há histórico de filiação partidária anterior verificado em fonte rastreável.$pf$ FROM candidatos c WHERE c.slug='renan-hallais' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Camila Falcão$pf$,$pf$Camila Falcão$pf$,'camila-falcao','PE','Governador',$pf$Unidade Popular$pf$,'UP','pre-candidato','pre-candidato',$pf$Camila Falcão, conhecida como Professora Camila, é pré-candidata ao Governo de Pernambuco em 2026 pela Unidade Popular (UP). É natural de Vitória de Santo Antão, no Agreste pernambucano, formada em História e atua como professora da educação popular. Atuou na organização do movimento estudantil da Universidade Federal Rural de Pernambuco (UFRPE) e foi coordenadora geral do Diretório Central dos Estudantes Odijas Carvalho de Souza. Integrou o Movimento Luta de Classes, participando de mobilizações de trabalhadores da limpeza urbana, professores e profissionais de enfermagem. Atualmente coordena o Movimento de Mulheres Olga Benario, voltado ao enfrentamento de feminicídios e outras formas de violência contra mulheres e crianças. Sua pré-candidatura foi anunciada no congresso extraordinário da UP, em 26 de abril de 2026, no Recife, evento que contou com a presença de Samara Martins, pré-candidata do partido à Presidência da República.$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='camila-falcao');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','UP',2026,NULL,$pf$Pré-candidata lançada pela Unidade Popular (UP) ao Governo de Pernambuco, anunciada no congresso extraordinário do partido em 26/04/2026, no Recife (fonte: https://jc.uol.com.br/politica/2026/04/27/unidade-popular-lanca-professora-camila-como-pre-candidata-ao-governo-de-pernambuco.html). Histórico de militância em movimentos sociais ligados à UP (movimento estudantil UFRPE, Movimento Luta de Classes, Movimento de Mulheres Olga Benario). Não há registro de filiação partidária anterior verificado em fonte rastreável.$pf$ FROM candidatos c WHERE c.slug='camila-falcao' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Tony Garcia$pf$,$pf$Tony Garcia$pf$,'tony-garcia','PR','Governador',$pf$Democracia Crista$pf$,'DC','pre-candidato','pre-candidato',$pf$Tony Garcia (nome completo Antônio Celso Garcia), nascido em 23 de abril de 1953 em São Paulo, é empresário e político radicado no Paraná. Atuou em publicidade, mercado imobiliário, distribuição de valores mobiliários e exploração de postos de combustível no estado. Na política desde os anos 1990, foi candidato a senador pelo PRN em 1990 (25,81% dos votos), candidato a prefeito de Curitiba em 1992 e novamente candidato a senador em 1994 (13,88%). Foi eleito deputado estadual do Paraná pelo PPB no mandato de 1999 a 2002, seu único cargo eletivo, e presidiu em 2001 a CPI das Telecomunicações da Assembleia, suspensa após investigar denúncias de grampos ilegais. Em 2002 disputou novamente o Senado (7,21%). Ganhou notoriedade nacional como delator: em 2018 fez delação premiada contra o ex-governador Beto Richa, com gravações feitas entre 2010 e 2015, e em 2023 afirmou ter atuado como 'agente infiltrado' a serviço da força-tarefa da Lava Jato e do então juiz Sergio Moro. Filiou-se ao DC em 2026 dentro de uma articulação anti-Moro (com Ricardo Gomyde na presidência estadual do partido e ligada à pré-candidatura presidencial de Aldo Rebelo), lançando-se pré-candidato ao governo do Paraná com a promessa de confrontar diretamente Sergio Moro.$pf$,'https://upload.wikimedia.org/wikipedia/commons/1/10/Tony_Garcia_propaganda_de_1990_%28cropped%29.jpg',true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='tony-garcia');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','DC',2026,NULL,$pf$Filiacao partidaria documentada: candidato a senador pelo PRN (1990); deputado estadual eleito pelo PPB (mandato 1999-2002); filiou-se ao DC (Democracia Cristã) em 2026 para a pre-candidatura ao governo do Parana. Fontes: https://pt.wikipedia.org/wiki/Tony_Garcia_(pol%C3%ADtico) ; https://www.esmaelmorais.com.br/tony-garcia-dc-gomyde-aldo-rebelo-parana/ ; https://www.brasil247.com/blog/tony-garcia-entra-na-disputa-pelo-governo-do-parana-e-promete-confronto-direto-com-sergio-moro$pf$ FROM candidatos c WHERE c.slug='tony-garcia' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Renato Gomes$pf$,$pf$Renato Gomes$pf$,'renato-gomes','MS','Governador',$pf$Democracia Crista$pf$,'DC','pre-candidato','pre-candidato',$pf$Renato Wanderley Gomes é economista, com cerca de 39 anos, formado no Rio de Janeiro e radicado em Campo Grande (MS). Tem carreira de aproximadamente 15 anos no sistema financeiro e, ao retornar a Mato Grosso do Sul, passou a atuar em advocacia e contabilidade empresarial, atendendo a uma carteira de empresas na capital. Católico, ganhou visibilidade nas redes sociais como crítico de 'erros' de políticos de direita e do bolsonarismo sul-mato-grossense. Filiou-se ao Democracia Cristã (DC) e foi lançado como pré-candidato ao Governo de Mato Grosso do Sul para 2026, com discurso de gestão técnica e ética; em pesquisas iniciais aparece na faixa de 3% a 4,5% das intenções de voto.$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='renato-gomes');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','DC',2026,NULL,$pf$Filiou-se ao Democracia Cristã (DC) por volta de abril de 2026 com o objetivo declarado de disputar o governo do estado; lançado/anunciado como pré-candidato ao Governo de MS pelo DC para 2026. Fontes: https://www.ojacare.com.br/2026/04/02/critico-de-erros-da-direita-economista-se-filia-ao-dc-para-ser-candidato-a-governador ; https://ndmais.com.br/politica/eleicoes-em-mato-grosso-do-sul-2026/$pf$ FROM candidatos c WHERE c.slug='renato-gomes' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Jeferson Bezerra$pf$,$pf$Jeferson Bezerra$pf$,'jeferson-bezerra','MS','Governador',$pf$Agir$pf$,'AGIR','pre-candidato','pre-candidato',$pf$Jefferson Bezerra é jornalista e proprietário do site de notícias MSNoticias (também referido como MGSNoticias), e presidente estadual do partido Agir em Mato Grosso do Sul. Foi oficializado como pré-candidato ao Governo de Mato Grosso do Sul para as eleições de 2026 em maio de 2026, com a indicação aprovada pela direção nacional do partido, por meio do presidente nacional Daniel Tourinho. Segundo o próprio pré-candidato, a candidatura ao governo serve também para atrair novos nomes e estruturar chapas do Agir para deputado estadual e federal no estado; em pesquisa recente apareceu com cerca de 1% das intenções de voto.$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='jeferson-bezerra');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','AGIR',2026,NULL,$pf$Presidente estadual do Agir em Mato Grosso do Sul; oficializado como pré-candidato ao Governo de MS pelo Agir em maio de 2026, com aprovação da direção nacional (presidente nacional Daniel Tourinho). Fontes: https://www.capitalnews.com.br/politica-e-poder/politica/agir-oficializa-jefferson-bezerra-como-pre-candidato-ao-governo-de-mato-grosso-do-sul/439798 ; https://progresso.com.br/index.php/2026/05/20/partido-agir-anuncia-jornalista-como-pre-candidato-a-governador/ . OBSERVAÇÃO IMPORTANTE: o nome informado na tarefa é 'Jeferson Bezerra' (um f), mas todas as fontes da imprensa grafam 'Jefferson Bezerra' (dois f). Recomenda-se confirmar a grafia oficial junto ao TSE/partido antes de publicar.$pf$ FROM candidatos c WHERE c.slug='jeferson-bezerra' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Rafael Luz$pf$,$pf$Rafael Luz$pf$,'rafael-luz','RJ','Governador',$pf$Partido Missao$pf$,'MISSAO','pre-candidato','pre-candidato',$pf$Rafael Luz, conhecido como Bombeiro Rafa, é pré-candidato ao Governo do Rio de Janeiro em 2026 pelo partido Missão (sigla recém-aprovada pelo TSE e nascida do Movimento Brasil Livre, o MBL). É bombeiro militar, ex-policial militar, pedagogo, filósofo e especialista em segurança escolar; carioca de Copacabana, atuou no 17º Grupamento de Bombeiros e participou da resposta ao incêndio do Museu Nacional em 2018. Apresenta perfil jovem e conservador, com campanha orientada a segurança pública, combate à corrupção e defesa de valores liberais. Já se apresenta nas redes como pré-candidato a governador.$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='rafael-luz');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','MISSAO',2026,NULL,$pf$Pré-candidato pelo partido Missão (ex-MBL), sigla recém-aprovada pelo TSE. Filiação dependente da abertura do sistema de filiações do TSE no momento da reportagem (nov/2025). Fonte: https://diariodorio.com/partido-missao-aposta-em-bombeiro-rafael-luz-para-disputar-o-governo-do-rj-em-2026/$pf$ FROM candidatos c WHERE c.slug='rafael-luz' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Wilson Witzel$pf$,$pf$Wilson Witzel$pf$,'wilson-witzel','RJ','Governador',$pf$Democrata$pf$,'D35','pre-candidato','pre-candidato',$pf$Wilson Witzel é pré-candidato ao Governo do Rio de Janeiro em 2026 pelo partido Democrata (antigo Partido da Mulher Brasileira, PMB), lançado em 09/06/2026 na sede estadual da legenda. Advogado, ex-fuzileiro naval e ex-juiz federal, nasceu em Jundiaí (SP) em 19/02/1968. Foi governador do RJ a partir de 2019, eleito em 2018 com apoio da família Bolsonaro, e sofreu impeachment em 2021 (afastado por 10 votos a 0 no Tribunal Especial Misto) sob acusação de comandar esquema de desvio de verbas da saúde, incluindo de hospitais de campanha de Covid-19, ficando cinco anos inelegível. Retorna à disputa após o fim do período de inelegibilidade, com plataforma de segurança 'tolerância zero', escolas cívico-militares e Secretaria de Capelania.$pf$,'https://upload.wikimedia.org/wikipedia/commons/thumb/6/62/Wilson_Witzel_com_faixa_de_Governador_2_%28cropped%29.jpg/250px-Wilson_Witzel_com_faixa_de_Governador_2_%28cropped%29.jpg',true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='wilson-witzel');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','D35',2026,NULL,$pf$Filiação ao partido Democrata, antigo PMB (renomeado pelo TSE em 02/12/2025, número eleitoral 35). Pré-candidatura lançada em 09/06/2026 na sede do partido no Rio. Witzel foi eleito governador em 2018 (apoio da família Bolsonaro), sofreu impeachment em 2021 e ficou cinco anos inelegível, período encerrado às vésperas de 2026. Fontes: https://www.dgabc.com.br/Noticia/4327972/wilson-witzel-lanca-pre-candidatura-ao-governo-do-rio-de-janeiro ; https://www.tse.jus.br/comunicacao/noticias/2025/Dezembro/partido-da-mulher-brasileira-pmb-passara-a-se-chamar-democrata$pf$ FROM candidatos c WHERE c.slug='wilson-witzel' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Ricardo Marques$pf$,$pf$Ricardo Marques$pf$,'ricardo-marques','SE','Governador',$pf$Partido Liberal$pf$,'PL','pre-candidato','pre-candidato',$pf$Ricardo Marques e jornalista e atual vice-prefeito de Aracaju (eleito em 2024 na chapa de Emilia Correa). Foi vereador de Aracaju em primeiro mandato (2021-2024). Anunciou pre-candidatura ao Governo de Sergipe em 2026 pelo PL, em articulacao com o palanque de Flavio Bolsonaro (pre-candidato a presidente pelo PL) e Rodrigo Valadares (que comanda a chapa do PL em Sergipe).$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='ricardo-marques');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','PL',2026,NULL,$pf$Filiado ao PL. Eleito vice-prefeito de Aracaju em 2024 na chapa de Emilia Correa (PL). Pre-candidatura ao governo confirmada apos a janela partidaria em abril de 2026. Fontes: https://infonet.com.br/noticias/politica/ricardo-marques-anuncia-pre-candidatura-ao-governo-de-sergipe-pelo-pl/ ; https://pt.wikipedia.org/wiki/Elei%C3%A7%C3%B5es_estaduais_em_Sergipe_em_2026$pf$ FROM candidatos c WHERE c.slug='ricardo-marques' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Emanuel Cacho$pf$,$pf$Emanuel Cacho$pf$,'emanuel-cacho','SE','Governador',$pf$PSDB$pf$,'PSDB','pre-candidato','pre-candidato',$pf$Emanuel Cacho e advogado e presidente da Federacao PSDB-Cidadania em Sergipe, designado pela direcao nacional do PSDB. Atua na area juridica, incluindo passagem como Secretario de Estado da Justica de Sergipe, e e ligado a entidades da advocacia criminal. E o pre-candidato do PSDB ao Governo de Sergipe em 2026.$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='emanuel-cacho');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','PSDB',2026,NULL,$pf$Filiado ao PSDB, presidente da Federacao PSDB-Cidadania em Sergipe (designacao confirmada pela direcao nacional do PSDB em abril de 2026). A pagina da Wikipedia das eleicoes 2026 e a propria nota do PSDB confirmam a filiacao atual e a pre-candidatura ao governo. Fontes: https://www.psdb.org.br/acompanhe/noticias/emanuel-cacho-assume-presidencia-da-federacao-psdb-cidadania-em-sergipe/ ; https://pt.wikipedia.org/wiki/Elei%C3%A7%C3%B5es_estaduais_em_Sergipe_em_2026$pf$ FROM candidatos c WHERE c.slug='emanuel-cacho' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Dr. Helton Monteiro$pf$,$pf$Dr. Helton Monteiro$pf$,'dr-helton-monteiro','SE','Governador',$pf$Partido Socialismo e Liberdade$pf$,'PSOL','pre-candidato','pre-candidato',$pf$Dr. Helton Monteiro e medico (formado em 2004), servidor publico e dirigente sindical, presidente (licenciado) do Sindicato dos Medicos do Estado de Sergipe (Sindimed). Tem historico no movimento estudantil (UFS, a partir de 1994) e sindical (direcao do Sindimed, CUT Sergipe, Federacao Nacional dos Medicos e, mais recentemente, Federacao Medica Brasileira). Em plenaria do PSOL em 7 de abril de 2026, foi definido como pre-candidato ao Governo de Sergipe, com pauta de defesa do SUS e do servico publico e oposicao a privatizacoes.$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='dr-helton-monteiro');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','PSOL',2026,NULL,$pf$Filiado ao PT nos anos 1990; ingressou no PSOL em 2022. Definido como pre-candidato ao Governo de Sergipe pelo PSOL em plenaria estadual de 7 de abril de 2026. Fontes: https://www.clicksergipe.com.br/politica/4/106360/ ; https://infonet.com.br/noticias/politica/psol-anuncia-dr-helton-como-pre-candidato-ao-governo-de-sergipe/$pf$ FROM candidatos c WHERE c.slug='dr-helton-monteiro' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Sérgio Gonçalves$pf$,$pf$Sérgio Gonçalves$pf$,'sergio-goncalves','RO','Governador',$pf$Uniao Brasil$pf$,'UNIAO','pre-candidato','pre-candidato',$pf$Sérgio Gonçalves da Silva, nascido em 28 de maio de 1974, é o vice-governador de Rondônia desde 1º de janeiro de 2023, na chapa do governador Marcos Rocha. Filiado ao União Brasil, é empresário do ramo de supermercados (filho de José Gonçalves, fundador do Supermercado Gonçalves) e formado em Administração. Comandou a Secretaria de Estado do Desenvolvimento Econômico (Sedec) de Rondônia por cerca de dois anos e meio, até ser exonerado pelo governador Marcos Rocha em julho de 2025, em meio a conflito político. É pré-candidato ao Governo de Rondônia em 2026; em maio de 2025 reafirmou publicamente, por vídeo, que mantém a pré-candidatura e negou articulação para assumir vaga no TCE-RO. A vaga de governador deve abrir porque Rocha é pré-candidato ao Senado.$pf$,'https://upload.wikimedia.org/wikipedia/commons/b/b9/FRO220001609510_div.jpg',true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='sergio-goncalves');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','UNIAO',2026,NULL,$pf$Filiado ao União Brasil desde 2022, partido pelo qual foi eleito vice-governador de Rondônia (mandato 2023-2026) na chapa de Marcos Rocha. Mantém-se no União Brasil como pré-candidato ao governo em 2026. Fonte: https://en.wikipedia.org/wiki/S%C3%A9rgio_Gon%C3%A7alves_(Brazilian_politician) e https://www.tudorondonia.com/noticias/vice-governador-sergio-goncalves-confirma-pre-candidatura-ao-governo-e-nega-articulacao-para-vaga-no-tce-ro,140402.shtml$pf$ FROM candidatos c WHERE c.slug='sergio-goncalves' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Ricardo Frota$pf$,$pf$Ricardo Frota$pf$,'ricardo-frota','RO','Governador',$pf$Partido Democratico Trabalhista$pf$,'PDT','pre-candidato','pre-candidato',$pf$Ricardo Frota, nascido em 1º de outubro de 1979 em Porto Velho (RO), é advogado, jornalista e analista político. De origem pobre, estudou em escola pública e, antes de se formar, trabalhou como vendedor de cachorro-quente, de dindin/sorvete caseiro e ajudante de pedreiro. Disputou sua primeira eleição em 2012, para vereador, e em 2024 foi candidato a prefeito de Porto Velho pelo partido Novo (número 30). Em 2026 deixou o Novo e se filiou ao PDT, partido ligado ao senador Acir Gurgacz, anunciando pré-candidatura ao Governo de Rondônia. A base de seu programa, segundo ele, é 'organizar a casa': enxugar a máquina pública, reduzir cargos comissionados e substituir contratos emergenciais por concursos públicos.$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='ricardo-frota');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','PDT',2026,NULL,$pf$Foi candidato a prefeito de Porto Velho em 2024 pelo partido Novo (número 30). Em 2026 deixou o Novo e se filiou ao PDT, partido do senador Acir Gurgacz, pelo qual lançou pré-candidatura ao Governo de Rondônia. Fontes: https://www.euideal.com/noticia/59810/porto-velho/politica/ricardo-frota-deixa-o-novo-se-filia-ao-pdt-e-anuncia-pre-candidatura-ao-governo-de-rondonia.html e https://www.tudorondonia.com/noticias/ricardo-frota-deixa-novo-e-vai-ao-pdt-em-apoio-a-acir-gurgacz-,156641.shtml$pf$ FROM candidatos c WHERE c.slug='ricardo-frota' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Thor Dantas$pf$,$pf$Thor Dantas$pf$,'thor-dantas','AC','Governador',$pf$Partido Socialista Brasileiro$pf$,'PSB','pre-candidato','pre-candidato',$pf$Thor Dantas e medico infectologista e pre-candidato ao Governo do Acre em 2026 pelo PSB. Em abril de 2026 assumiu a presidencia estadual do PSB no Acre, sucedendo Cesar Messias, e afirmou que sua pre-candidatura ao governo entrava em um "novo ciclo". Defende gestao mais tecnica e critica a baixa capacidade de execucao de investimentos publicos no estado, com a proposta de "resgatar a capacidade de dialogo, de planejamento e de investimento". Articula uma frente de esquerda ampla com PSB, PT, PV, PSOL, PCdoB, Rede e Podemos.$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='thor-dantas');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','PSB',2026,NULL,$pf$Filiado ao PSB; assumiu a presidencia estadual do PSB no Acre em abril de 2026, sucedendo Cesar Messias (fonte: Portal Acre, abr/2026). Pre-candidatura ao governo declarada desde setembro de 2025.$pf$ FROM candidatos c WHERE c.slug='thor-dantas' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Eudo Raffael$pf$,$pf$Eudo Raffael$pf$,'eudo-raffael','AC','Governador',$pf$Partido Comunista Brasileiro$pf$,'PCB','pre-candidato','pre-candidato',$pf$Eudo Raffael e presidente do Sindicato dos Bancarios do Acre e e apontado pelo PCB como um dos nomes para a pre-candidatura ao Governo do Acre em 2026. O PCB oficializou em manifesto a decisao de disputar o governo do estado em 2026 e iniciou debate interno para definir o nome que encabecaria a chapa, processo no qual Eudo Raffael foi apresentado. Aparece como pre-candidato em levantamentos de junho de 2026 (Parana Pesquisas, Real Time Big Data).$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='eudo-raffael');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','PCB',2026,NULL,$pf$Ligado ao PCB; presidente do Sindicato dos Bancarios do Acre. O PCB formalizou em manifesto a decisao de disputar o governo do Acre em 2026 e apresentou nomes em debate interno, entre eles Eudo Raffael (fontes: empateacre.com; Metropoles). Ate as fontes consultadas (jun/2026), a candidatura aparecia como pre-candidatura/nome em definicao, nao confirmada por convencao.$pf$ FROM candidatos c WHERE c.slug='eudo-raffael' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Robério Paulino$pf$,$pf$Robério Paulino$pf$,'roberio-paulino','RN','Governador',$pf$Partido Socialismo e Liberdade$pf$,'PSOL','pre-candidato','pre-candidato',$pf$Robério Paulino é pré-candidato ao Governo do Rio Grande do Norte em 2026 pelo PSOL. Economista formado pela USP e professor do Instituto de Políticas Públicas da UFRN, com pós-doutorado na SOAS (University of London), é vereador de Natal e integra a direção do PSOL-RN. Já disputou o governo do estado em 2014, quando obteve cerca de 130 mil votos (em torno de 8,7% a 9%), ficando em terceiro lugar e ajudando a levar a eleição ao segundo turno.$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='roberio-paulino');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','PSOL',2026,NULL,$pf$Filiado ao PSOL, exerce mandato de vereador em Natal e integra a direção estadual do PSOL-RN. Em março de 2026 o PSOL-RN oficializou sua pré-candidatura ao Governo do RN (Tribuna do Norte; Agora RN; Saiba Mais, mar/2026).$pf$ FROM candidatos c WHERE c.slug='roberio-paulino' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Dário Barbosa$pf$,$pf$Dário Barbosa$pf$,'dario-barbosa','RN','Governador',$pf$Partido Socialista dos Trabalhadores Unificado$pf$,'PSTU','pre-candidato','pre-candidato',$pf$Dário Barbosa é pré-candidato ao Governo do Rio Grande do Norte em 2026 pelo PSTU. Professor aposentado das redes estadual do RN e municipal de Natal, tem histórico ligado ao movimento sindical potiguar. É figura recorrente nas disputas eleitorais do estado, com candidaturas anteriores como a ao governo do RN em 2018 e ao Senado em 2022. Sua pré-candidatura ao governo foi anunciada pelo PSTU em abril de 2026.$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='dario-barbosa');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','PSTU',2026,NULL,$pf$Filiado ao PSTU. Em abril de 2026 o PSTU lançou sua pré-candidatura ao Governo do RN, em chapa com pré-candidaturas ao Senado (Rosália Fernandes e Luciana Lima). Já havia disputado o governo do RN em 2018 e o Senado em 2022 pelo PSTU (Novo Notícias; Agora RN; Saiba Mais; Tribuna do Norte, 2026).$pf$ FROM candidatos c WHERE c.slug='dario-barbosa' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Vera Lúcia$pf$,$pf$Vera Lúcia$pf$,'vera-lucia','SP','Governador',$pf$Partido Socialista dos Trabalhadores Unificado$pf$,'PSTU','pre-candidato','pre-candidato',$pf$Vera Lúcia Pereira da Silva Salgado é pré-candidata ao Governo de São Paulo em 2026 pelo PSTU. Nascida em Inajá (PE) em 1967, é uma das fundadoras do PSTU em 1994, após sair do PT. Operária e sindicalista, é graduada em Ciências Sociais pela Universidade Federal de Sergipe e atualmente vive em São Paulo. Tem longa trajetória eleitoral pela legenda, sem nunca ter sido eleita: foi candidata à Presidência da República em 2018 e 2022, à Prefeitura de São Paulo em 2020 (a primeira mulher negra a disputar a prefeitura paulistana), ao governo de Sergipe, à Prefeitura de Aracaju e a deputada federal. Apresenta uma pré-candidatura socialista voltada às demandas da classe trabalhadora.$pf$,'https://upload.wikimedia.org/wikipedia/commons/f/fc/-2022-08-20-_Vera-e-Raquel_07_%2852305375940%29_%28cropped%29.jpg',true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='vera-lucia');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','PSTU',2026,NULL,$pf$Filiada ao PT de 1992 a 1993 (expulsa); cofundadora do PSTU em 1994, no qual permanece até hoje. Fonte: https://pt.wikipedia.org/wiki/Vera_L%C3%BAcia_(pol%C3%ADtica)$pf$ FROM candidatos c WHERE c.slug='vera-lucia' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Camilo Terra$pf$,$pf$Camilo Terra$pf$,'camilo-terra','SP','Governador',$pf$Partido Comunista Brasileiro$pf$,'PCB','pre-candidato','pre-candidato',$pf$Camilo Terra (nome completo Eduardo Camilo Terra dos Santos) é pré-candidato ao Governo de São Paulo em 2026 pelo PCB (Partido Comunista Brasileiro). Nascido em 11 de setembro de 1974, em São Sebastião (SP), é servidor público federal, com ensino superior completo. Em 2022 foi candidato a deputado federal por São Paulo pelo PCB (número 2155), não tendo sido eleito. Não possui cargo eletivo anterior.$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='camilo-terra');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','PCB',2026,NULL,$pf$Filiado ao PCB; concorreu a deputado federal por SP em 2022 pela legenda e é pré-candidato ao governo de SP em 2026 pelo mesmo partido. Fontes: https://pt.wikipedia.org/wiki/Elei%C3%A7%C3%B5es_estaduais_em_S%C3%A3o_Paulo_em_2026 ; resultado eleitoral 2022 (TSE/CNN). A pré-candidatura ao governo em 2026 consta na Wikipedia (fonte indicada na tarefa); ainda não há cobertura ampla da grande imprensa.$pf$ FROM candidatos c WHERE c.slug='camilo-terra' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
INSERT INTO candidatos (nome_completo,nome_urna,slug,estado,cargo_disputado,partido_atual,partido_sigla,status,situacao_candidatura,biografia,foto_url,publicavel,fonte_dados,ultima_atualizacao) SELECT $pf$Izadora Dias$pf$,$pf$Izadora Dias$pf$,'izadora-dias','SP','Governador',$pf$Partido da Causa Operaria$pf$,'PCO','pre-candidato','pre-candidato',$pf$Izadora Dias é pré-candidata ao Governo de São Paulo em 2026 pelo PCO (Partido da Causa Operária). Nascida em Barra Bonita (SP), é estudante na Universidade de São Paulo (USP) e militante do PCO desde 2018, quando se aproximou do partido pela campanha pela liberdade do ex-presidente Lula. Atua como articuladora de coletivo do partido e em veículos da Causa Operária. O PCO trata suas candidaturas como plataforma de propaganda do seu programa, não como solução eleitoral.$pf$,NULL,true,ARRAY['curadoria','varredura-cobertura-20260626'],now() WHERE NOT EXISTS (SELECT 1 FROM candidatos WHERE slug='izadora-dias');
INSERT INTO mudancas_partido (candidato_id,partido_anterior,partido_novo,ano,data_mudanca,contexto) SELECT c.id,'Historico anterior nao determinado','PCO',2026,NULL,$pf$Militante do PCO desde 2018; pré-candidata ao governo de São Paulo em 2026 pela legenda (candidatura a ser formalizada nas convenções partidárias previstas para meados de julho de 2026). Fontes: https://candidatos.pco.org.br/candidatos/izadora-dias/ ; https://candidatos.pco.org.br/estados29/sao-paulo/$pf$ FROM candidatos c WHERE c.slug='izadora-dias' AND NOT EXISTS (SELECT 1 FROM mudancas_partido m WHERE m.candidato_id=c.id);
